          </div>

          <div style={{ display: 'flex', flexWrap: 'wrap', gap: 8, justifyContent: 'center', animation: 'hIn 0.9s 0.9s both' }}>
            {STACK.slice(0, 8).map(t => (
              <span key={t} style={{ padding: '5px 14px', background: 'rgba(255,255,255,0.04)', border: '1px solid rgba(255,255,255,0.08)', borderRadius: 999, fontSize: '0.73rem', color: 'rgba(255,255,255,0.48)', fontWeight: 500 }}>{t}</span>
            ))}
          </div>
        </div>

        {/* Scroll cue */}
        <div style={{ position: 'absolute', bottom: 28, left: '50%', transform: 'translateX(-50%)', opacity: Math.max(0, 1 - prog * 12), display: 'flex', flexDirection: 'column', alignItems: 'center', gap: 5, transition: 'none' }}>
          <span style={{ fontSize: '0.58rem', color: 'rgba(255,255,255,0.3)', letterSpacing: '0.2em', textTransform: 'uppercase' }}>scroll</span>
          <div style={{ width: 1, height: 40, background: 'linear-gradient(to bottom, rgba(255,255,255,0.5), transparent)' }} />
          <ChevronDown size={14} color="rgba(255,255,255,0.3)" style={{ animation: 'bounce 1.8s ease-in-out infinite' }} />
        </div>

        {/* Bottom progress draw */}
        <div style={{ position: 'absolute', bottom: 0, left: 0, height: 2, width: `${prog * 100}%`, background: 'linear-gradient(90deg,#0057ff,#7c3aed)', boxShadow: '0 0 14px rgba(0,87,255,0.8)', transition: 'none' }} />
      </section>
    </div>
  );
}

