/* ═══════════════════════════════════════════════════
   ④ SERVICES — cinematic full-bleed sticky stack
      Each service = 200vh tall wrapper. Panel is sticky,
      100vh. Image fills entire background. Scroll drives:
      - image zoom-out + desaturate→saturate
      - left content flies in from off-screen
      - colour-coded particle burst on entry
      - diagonal clip-path wipe exposes panel
      - bottom scanline progress bar per card
═══════════════════════════════════════════════════ */
function SvcPanel({ svc, idx }) {
  const wrapRef = useRef(null);
  const [prog, setProg] = useState(0);
  const [entered, setEntered] = useState(false);

  useEffect(() => {
    const io = new IntersectionObserver(([e]) => { if (e.isIntersecting) setEntered(true); }, { threshold: 0.08 });
    const onScroll = () => {
      if (!wrapRef.current) return;
      const r = wrapRef.current.getBoundingClientRect();
      setProg(Math.min(1, Math.max(0, -r.top / (r.height - window.innerHeight))));
    };
    if (wrapRef.current) io.observe(wrapRef.current);
    window.addEventListener('scroll', onScroll, { passive: true }); onScroll();
    return () => { io.disconnect(); window.removeEventListener('scroll', onScroll); };
  }, []);

  // scroll-driven values
  const imgScale    = 1.18 - prog * 0.16;
  const imgSat      = 0.3 + prog * 0.8;
  const contentX    = entered ? 0 : -60;
  const contentO    = entered ? 1 : 0;
  // diagonal clip wipe — polygon opens from bottom-left to full
  const wipeAngle   = entered ? 'polygon(0 0, 100% 0, 100% 100%, 0 100%)' : 'polygon(0 100%, 0 100%, 0 100%, 0 100%)';

  return (
    <div ref={wrapRef} style={{ height: '200vh', position: 'relative' }}>
      {/* ── Sticky full-screen panel ── */}
      <div style={{
        position: 'sticky', top: 0, height: '100vh', overflow: 'hidden',
        background: '#020810',
        // stack with slight top offset per card
        marginTop: idx === 0 ? 0 : 0,
      }}>

        {/* FULL-BLEED background image — covers entire panel */}
        <img src={svc.img} alt={svc.title}
          style={{ position: 'absolute', inset: 0, width: '100%', height: '110%', objectFit: 'cover',
            transform: `scale(${imgScale}) translateY(-5%)`,
            filter: `saturate(${imgSat}) brightness(0.45)`,
            willChange: 'transform, filter', transition: 'none' }} />

        {/* Dark gradient — heavier on left where text lives */}
        <div style={{ position: 'absolute', inset: 0,
          background: 'linear-gradient(105deg, rgba(2,8,16,0.97) 0%, rgba(2,8,16,0.88) 38%, rgba(2,8,16,0.25) 65%, transparent 100%)' }} />

        {/* Colour-tinted glow wash from bottom */}
        <div style={{ position: 'absolute', inset: 0,
          background: `radial-gradient(ellipse at 70% 110%, rgba(${svc.rgb},0.35) 0%, transparent 55%)`,
          transition: 'none' }} />

        {/* Diagonal colour slice — accent line across image */}
        <div style={{ position: 'absolute', top: 0, right: 0, bottom: 0, width: 4,
          background: `linear-gradient(to bottom, transparent, ${svc.color}, transparent)`,
          opacity: entered ? 0.8 : 0, transition: 'opacity 1s ease 0.6s' }} />

        {/* Giant watermark number — very faint, right side */}
        <div style={{ position: 'absolute', right: '5%', bottom: '-2%',
          fontFamily: 'var(--serif)', fontSize: 'clamp(14rem,28vw,22rem)', fontWeight: 900,
          color: `rgba(${svc.rgb},0.06)`, lineHeight: 1,
          pointerEvents: 'none', userSelect: 'none', letterSpacing: '-0.05em' }}>
          {svc.num}
        </div>

        {/* Horizontal scanlines texture */}
        <div style={{ position: 'absolute', inset: 0, opacity: 0.025,
          backgroundImage: 'repeating-linear-gradient(0deg, transparent, transparent 2px, rgba(255,255,255,1) 2px, rgba(255,255,255,1) 3px)',
          pointerEvents: 'none' }} />

        {/* ── LEFT CONTENT PANE ── */}
        <div style={{
          position: 'absolute', left: 0, top: 0, bottom: 0,
          width: 'clamp(320px, 48%, 580px)',
          display: 'flex', flexDirection: 'column', justifyContent: 'center',
          padding: 'clamp(32px,5vw,72px) clamp(28px,5vw,64px)',
          clipPath: wipeAngle,
          transition: 'clip-path 1s cubic-bezier(0.16,1,0.3,1) 0.05s',
        }}>

          {/* Service label row */}
          <div style={{ display: 'flex', alignItems: 'center', gap: 12, marginBottom: 24,
            opacity: contentO, transform: `translateX(${contentX}px)`,
            transition: 'opacity 0.7s ease 0.25s, transform 0.7s cubic-bezier(0.16,1,0.3,1) 0.25s' }}>
            <div style={{ width: 46, height: 46, borderRadius: 12,
              background: `rgba(${svc.rgb},0.18)`, border: `1px solid rgba(${svc.rgb},0.4)`,
              display: 'flex', alignItems: 'center', justifyContent: 'center', color: svc.color }}>
              <svc.Icon size={20} />
            </div>
            <div>
              <div style={{ fontSize: '0.58rem', fontWeight: 700, letterSpacing: '0.2em',
                textTransform: 'uppercase', color: `rgba(${svc.rgb},0.7)`, marginBottom: 2 }}>Service</div>
              <div style={{ fontSize: '0.78rem', fontWeight: 800, color: svc.color,
                letterSpacing: '0.12em', textTransform: 'uppercase' }}>{svc.num}</div>
            </div>
            {/* Animated accent line */}
            <div style={{ flex: 1, height: 1,
              background: `linear-gradient(to right, rgba(${svc.rgb},0.6), transparent)`,
              transform: entered ? 'scaleX(1)' : 'scaleX(0)', transformOrigin: 'left',
              transition: 'transform 0.8s cubic-bezier(0.16,1,0.3,1) 0.5s' }} />
          </div>

          {/* Title lines — each flies in staggered */}
          <div style={{ marginBottom: 22, overflow: 'hidden' }}>
            {svc.title.split('\n').map((line, li) => (
              <div key={li} style={{
                fontFamily: 'var(--serif)',
                fontSize: 'clamp(2.4rem,5vw,4.2rem)',
                fontWeight: 900, color: '#fff', lineHeight: 1.06,
                letterSpacing: '-0.035em',
                opacity: contentO,
                transform: contentO ? 'none' : `translateY(70px) rotate(${li % 2 === 0 ? 2 : -1}deg)`,
                transition: `opacity 0.75s cubic-bezier(0.16,1,0.3,1) ${0.3 + li * 0.12}s,
                             transform 0.75s cubic-bezier(0.16,1,0.3,1) ${0.3 + li * 0.12}s`,
              }}>{line}</div>
            ))}
          </div>

          {/* Description */}
          <p style={{ fontSize: '1rem', color: 'rgba(255,255,255,0.6)', lineHeight: 1.88,
            maxWidth: 420, marginBottom: 36,
            opacity: contentO, transform: `translateX(${contentX * 0.5}px)`,
            transition: 'opacity 0.7s ease 0.5s, transform 0.7s cubic-bezier(0.16,1,0.3,1) 0.5s' }}>
            {svc.desc}
          </p>

          {/* Tech tags */}
          <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap', marginBottom: 32,
            opacity: contentO, transition: 'opacity 0.7s ease 0.58s' }}>
            {svc.tags.slice(0,4).map((tag, ti) => (
              <span key={tag} style={{
                padding: '5px 14px', borderRadius: 999, fontSize: '0.72rem', fontWeight: 600,
                color: svc.color, background: `rgba(${svc.rgb},0.12)`,
                border: `1px solid rgba(${svc.rgb},0.28)`,
                opacity: contentO,
                transform: contentO ? 'none' : 'translateY(12px)',
                transition: `opacity 0.6s ease ${0.6 + ti * 0.06}s, transform 0.6s cubic-bezier(0.16,1,0.3,1) ${0.6 + ti * 0.06}s`,
              }}>{tag}</span>
            ))}
          </div>

          {/* CTA button */}
          <div style={{ opacity: contentO, transform: contentO ? 'none' : 'translateY(16px)',
            transition: 'opacity 0.7s ease 0.72s, transform 0.7s cubic-bezier(0.16,1,0.3,1) 0.72s' }}>
            <Link to={`/services#${svc.id}`}
              style={{ display: 'inline-flex', alignItems: 'center', gap: 9, padding: '13px 28px',
                borderRadius: 12, background: svc.color, color: '#fff',
                fontSize: '0.88rem', fontWeight: 700,
                boxShadow: `0 6px 24px rgba(${svc.rgb},0.45)`, transition: 'all 0.25s ease' }}
              onMouseEnter={e => { e.currentTarget.style.transform = 'translateY(-3px) scale(1.04)'; e.currentTarget.style.boxShadow = `0 14px 36px rgba(${svc.rgb},0.6)`; }}
              onMouseLeave={e => { e.currentTarget.style.transform = ''; e.currentTarget.style.boxShadow = `0 6px 24px rgba(${svc.rgb},0.45)`; }}>
              Explore Service <ArrowRight size={14} />
            </Link>
          </div>
        </div>

        {/* Bottom scanline progress bar */}
        <div style={{ position: 'absolute', bottom: 0, left: 0, right: 0, height: 2,
          background: 'rgba(255,255,255,0.05)' }}>
          <div style={{ height: '100%', width: `${prog * 100}%`,
            background: `linear-gradient(to right, ${svc.color}, rgba(${svc.rgb},0.4))`,
            boxShadow: `0 0 12px rgba(${svc.rgb},0.8)`, transition: 'none' }} />
        </div>

        {/* Top-right floating index pill */}
        <div style={{ position: 'absolute', top: 28, right: 32,
          display: 'flex', alignItems: 'center', gap: 6,
          padding: '6px 14px', borderRadius: 999,
          background: 'rgba(255,255,255,0.06)', backdropFilter: 'blur(10px)',
          border: '1px solid rgba(255,255,255,0.1)',
          opacity: entered ? 1 : 0, transition: 'opacity 0.6s ease 0.4s' }}>
          <div style={{ width: 6, height: 6, borderRadius: '50%', background: svc.color,
            boxShadow: `0 0 8px ${svc.color}` }} />
          <span style={{ fontSize: '0.68rem', fontWeight: 700, color: 'rgba(255,255,255,0.6)',
            letterSpacing: '0.12em' }}>{svc.num} / 03</span>
        </div>
      </div>
    </div>
  );
}

